      query: 'q',
      path: '',
      results: [fileEntry({ name: 'search-marker', path: 'docs/search-marker' })],
    });

    const resultsB = rootB.querySelector('.results') as HTMLElement;
    const resultsA = rootA.querySelector('.results') as HTMLElement;
